import random

def miller_rabin(n, k=5):
    """
    Miller-Rabin primality test.

    Args:
        n: The number to test for primality.
        k: The number of rounds of testing to perform (higher is more accurate).

    Returns:
        True if n is likely prime, False if n is composite.
    """
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0:
        return False

    # Find (s, r) pair such that n-1 = 2**s * r such that r is odd
    s = 0
    r = n - 1
    while r % 2 == 0:
        s += 1
        r //= 2

    # Do k tests
    for _ in range(k):
        a = random.randrange(2, n - 1)
        x = pow(a, r, n)

        if x == 1 or x == n - 1:
            continue

        for _ in range(s - 1):
            x = pow(x, 2, n)
            if x == n - 1:
                break
        else:
            return False  # composite

    return True  # probably prime

if __name__ == '__main__':
    # Example usage
    number_to_test = 29
    if miller_rabin(number_to_test):
        print(f"{number_to_test} is likely prime.")
    else:
        print(f"{number_to_test} is composite.")

